var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"면목 없군. 이번에도 그 여잘 이기지 못했어.","JPN":"面目ない。今回も彼女に勝てなかった。","ENG":"I have no excuse. I couldn't win against Yeonhwa again.","TWN":"真抱歉。這一次，我又輸給了蓮華。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"두 명이었다.","JPN":"2人だった。","ENG":"There were two of them.","TWN":"有兩個人。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"<color=#ffd34c>범</color>을 잡겠다는 사람이… 그 연화라는 여자 말고도 한 사람 더 있었어.","JPN":"<color=#ffd34c>虎</color>を倒そうとするやつが……そのレンカって女の他にも、もう一人いた。","ENG":"It wasn't just Yeonhwa who wanted to hunt the <color=#ffd34c>Tiger</color>… There was also someone else.","TWN":"除了那個叫蓮華的女人，還有另一個人，也說要抓老虎。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…둘이었다고?","JPN":"……2人？","ENG":"…Two, you say?","TWN":"…兩個人？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"나도 똑똑히 들었어. 어르신은 그 사람을 아버지라고 불렀지?","JPN":"私も確かに聞いたよ。あの人、おばあさんのお父さんなんだよね？","ENG":"I heard it clearly too. You called him \\"Father,\\" right, granny?","TWN":"我也聽得清清楚楚。阿姨叫那個人父親吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 사람도 자기 입으로 그렇다고 했고.","JPN":"あの人も認めていたし。","ENG":"And he said it himself.","TWN":"那個人自己也說是。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇다면 얼굴도 기억하겠군!","JPN":"なら、顔も覚えているのだな！","ENG":"Then you must remember his face!","TWN":"那麽，你應該也記得他的長相吧！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"수소문해서 그를 찾아보면 어떤가! 만나면 우리가 모르는 정보를 얻을 수 있을 테니…!","JPN":"聞き込みをして彼を探してみるのはどうだ！　会えれば我らが知らない情報を聞くこともできるはず……！","ENG":"What if we tracked him down? We might learn something we don't already know…!","TWN":"去打聽一下，試著找找他怎麼樣！如果見面了，或許能得到我們不知道的資訊…！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"살아있는 사람은 아닐 거다.","JPN":"既にこの世にはいない人間だろう。","ENG":"He's probably not alive anymore.","TWN":"他大概不在人世了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"과거에선 분명히 느껴졌던 그 사람의 존재가… 지금 이곳에선 느껴지지 않거든.","JPN":"過去でははっきりと感じたあの人の存在が、ここではまったく感じられない。","ENG":"The presence I once felt so clearly in the past… I can’t feel it here anymore.","TWN":"在過去，我明明能清楚感覺到那個人的存在…但在這裡，我感覺不到他的存在。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"미안하군. 내가 너무 성급했네.","JPN":"すまない。某が性急すぎた。","ENG":"My apologies. I got ahead of myself.","TWN":"抱歉。我太著急了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"죽었을 거라고 짐작은 했어.","JPN":"死んでいるだろうとは予想はしていた。","ENG":"I figured as much.","TWN":"我猜他應該已經死了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래도… 당신의 장치가 없었다면 과거에서조차 만나지 못했을 테지.","JPN":"だが……お前の装置がなかったら、過去ですら会うことはできなかっただろう。","ENG":"Still… without your device, I never would've met him, not even in the past.","TWN":"不過…如果沒有你的裝置，我連在過去也無法見到他吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 어렴풋하던 얼굴을 직접 본 것만으로도 나쁘진 않았어.","JPN":"薄っすらとしか思い出せなかった顔を実際見れただけでも、まあ悪くはなかった。","ENG":"I'm glad I got to see his face, even just once.","TWN":"光是親眼見到那個模糊的長相，就已經不錯了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"과거로 돌아가는 건 이번이 마지막이 아닐세.","JPN":"過去に戻るのはこれが最後ではない。","ENG":"That won't be our last time returning to the past.","TWN":"這次不會是最後一次回到過去。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화의 일행이라면 분명 나와도 무관하진 않을 테니. 할 수만 있다면 두 사람 모두를 돕겠다고 약속하지.","JPN":"レンカの仲間なら某とも無関係ではない。2人がまた会えるように、最善を尽くすと約束しよう。","ENG":"If he was with Yeonhwa, then I have a connection to him too. If I can, I'll do everything I can to help them both.","TWN":"既然是蓮華的同伴，那也和我脫不了關係。如果可以，我答應會幫助他們兩個人。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"…Yeah.","TWN":"…好。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 사람을 다시 만날 수 있다면, 나도 당신을 전력으로 돕겠어.","JPN":"あの人にまた会えるなら、私もお前を全力で手伝う。","ENG":"If there's a chance I could see him again, I'll back you with everything I've got.","TWN":"如果能再次見到那個人，我也會全力幫助你。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"라고 멋지게 결의를 다졌지만, 모아둔 이터니움이 이번에 완전히 바닥났습니다.","JPN":"……と、カッコよく決意表明しましたが、集めておいたエタニウムが底をついてしまいましたよ。","ENG":"Well, dramatic vows aside, we're totally out of Eternium.","TWN":"說得這麼帥氣，但我收集的永恆之金這次徹底用光了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"과.위.장을 가동하려면 다시 그 많은 양을 구해야 할 텐데, 쉽진 않겠네.","JPN":"過向装を稼働するにはまたあの量を集めないといけないけど、骨が折れるね。","ENG":"And we'll need a lot more if we're using DTP again. That won't be easy.","TWN":"要啟動回裝置，又要再找那麼多永恆之金，這可不容易。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"돈을 마련할 수단이라면 있다.","JPN":"金を調達する手段ならある。","ENG":"I have a way to get us funds.","TWN":"我有辦法籌錢。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"우리가 동굴에서 찾은 거 말이야.","JPN":"私たちが洞窟で見つけたあれだ。","ENG":"Remember what we found in the cave?","TWN":"我們在洞穴裡找到的那個。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응? 설마 차원함선 말하는 거야? 그걸 팔기라도 하자고?","JPN":"うん？　まさか次元艦船のこと？　あれを売るの？","ENG":"Huh? You mean the dimensional ship? You want to sell that thing?","TWN":"嗯？你說的是次元艦船嗎？把它賣掉？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이터니움 드라이브는 못 팔아도, 그 밖에 쓸만한 부품을 건질 순 있겠지.","JPN":"エタニウムドライブは売れなくても、他に使えそうな部品は手に入るだろう。","ENG":"Even if we can't sell the Eternium Drive, we can salvage useful parts.","TWN":"就算賣不掉永恆之金驅動器，也能從裡面找到其他有用的零件吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저기요. 관리국 출신이던 사람들이 그런 말 해도 돼?","JPN":"ちょっと、管理局出身の人がそんなこと言っていいの？","ENG":"Hey, are ex-Administration officials even allowed to say stuff like that?","TWN":"喂。你們兩個管理局出身的人說這種話，好嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};